	"fmt"
	"strings"
)

type Product struct {
	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Validate orderBy - only allow known column names to prevent SQL injection
	validColumns := map[string]string{
		"id":    "id",
		"name":  "name",
		"price": "price",
	}

	column, ok := validColumns[strings.ToLower(orderBy)]
	if !ok {
		return nil, fmt.Errorf("invalid orderBy column: %s", orderBy)
	}

	// Validate sortDir - only allow ASC or DESC
	direction := strings.ToUpper(sortDir)
	if direction != "ASC" && direction != "DESC" {
		return nil, fmt.Errorf("invalid sort direction: %s, must be ASC or DESC", sortDir)
	}

	// Build the query with validated inputs
	// Note: We use fmt.Sprintf here because ORDER BY clauses cannot use parameterized queries
	// The inputs are validated against a whitelist, so this is safe from SQL injection
	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", column, direction)

	// Execute the query
	rows, err := db.Query(query)
	if err != nil {
		return nil, fmt.Errorf("failed to query products: %w", err)
	}
	defer rows.Close()

	// Scan the results
	var products []Product
	for rows.Next() {
		var p Product
		if err := rows.Scan(&p.ID, &p.Name, &p.Price); err != nil {
			return nil, fmt.Errorf("failed to scan product: %w", err)
		}
		products = append(products, p)
	}

	// Check for any errors that occurred during iteration
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("error iterating products: %w", err)
	}

	return products, nil
}

